import{_ as a,a as t,b as r,c as d,d as n,e as o}from"./chunks/查询额度成功.BKueuYqe.js";import{_ as l,o as i,c as s,a2 as p}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Dropbox Kanalı Ekleme","description":"","frontmatter":{},"headers":[],"relativePath":"tr-TR/upload/dropbox.md","filePath":"tr-TR/upload/dropbox.md","lastUpdated":1781962217000}'),c={name:"tr-TR/upload/dropbox.md"};function u(h,e,b,k,m,y){return i(),s("div",null,[...e[0]||(e[0]=[p('<h1 id="dropbox-kanalı-ekleme" tabindex="-1">Dropbox Kanalı Ekleme <a class="header-anchor" href="#dropbox-kanalı-ekleme" aria-label="Permalink to &quot;Dropbox Kanalı Ekleme&quot;">​</a></h1><h2 id="once-gerekenler" tabindex="-1">Önce Gerekenler <a class="header-anchor" href="#once-gerekenler" aria-label="Permalink to &quot;Önce Gerekenler&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Gereken</th><th>Neden gerekir</th></tr></thead><tbody><tr><td>Dropbox hesabı</td><td>Giriş yapmak ve app yetkilendirmek için</td></tr><tr><td>Dropbox app</td><td><code>App Key</code> ve <code>App Secret</code> oluşturmak için</td></tr><tr><td>ImgBed alan adınız</td><td>OAuth redirect URI için</td></tr><tr><td>Kullanılabilir Dropbox depolama alanı</td><td>Dosyaların gerçekten saklanacağı yer</td></tr></tbody></table><h2 id="kurulum-adımları" tabindex="-1">Kurulum Adımları <a class="header-anchor" href="#kurulum-adımları" aria-label="Permalink to &quot;Kurulum Adımları&quot;">​</a></h2><h3 id="_1-dropbox-app-olusturun" tabindex="-1">1. Dropbox App Oluşturun <a class="header-anchor" href="#_1-dropbox-app-olusturun" aria-label="Permalink to &quot;1. Dropbox App Oluşturun&quot;">​</a></h3><ol><li>Dropbox App Console&#39;u açın:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://www.dropbox.com/developers/apps</span></span></code></pre></div><ol start="2"><li>Yeni app oluşturun.</li><li>Access type için şunu seçin:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>App folder</span></span></code></pre></div><ol start="4"><li>App için tanıyabileceğiniz bir ad verin, örneğin <code>imgbed-app</code>.</li><li>Oluşturulduktan sonra app ayrıntı sayfasını açın.</li></ol><p>Önerilen erişim türü:</p><table tabindex="0"><thead><tr><th>Access Type</th><th>Öneri</th></tr></thead><tbody><tr><td><code>App folder</code></td><td>Önerilir. ImgBed&#39;in dosya saklama biçimine uygundur.</td></tr><tr><td><code>Full Dropbox</code></td><td>Önerilmez. ImgBed&#39;in tüm hesaba erişmesine gerek yoktur.</td></tr></tbody></table><p><img src="'+a+'" alt="Dropbox app oluşturma" loading="lazy"></p><h3 id="_2-redirect-uri-ekleyin" tabindex="-1">2. Redirect URI Ekleyin <a class="header-anchor" href="#_2-redirect-uri-ekleyin" aria-label="Permalink to &quot;2. Redirect URI Ekleyin&quot;">​</a></h3><p>Dropbox app ayrıntı sayfasında OAuth veya Redirect URI ayarlarını bulun ve şunu ekleyin:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/api/oauth/dropbox/callback</span></span></code></pre></div><p>Yönetim panelini birden fazla alan adından kullanıyorsanız her eşleşen callback URL&#39;yi ekleyin.</p><p><img src="'+t+'" alt="Redirect URI yapılandırma" loading="lazy"></p><h3 id="_3-app-permissions-yapılandırın" tabindex="-1">3. App Permissions Yapılandırın <a class="header-anchor" href="#_3-app-permissions-yapılandırın" aria-label="Permalink to &quot;3. App Permissions Yapılandırın&quot;">​</a></h3><p><code>Permissions</code> sekmesini açın ve en az şu scopes değerlerini etkinleştirin:</p><table tabindex="0"><thead><tr><th>Scope</th><th>Zorunlu</th><th>Amaç</th></tr></thead><tbody><tr><td><code>account_info.read</code></td><td>Evet</td><td>Hesap ve kota bilgisini okur</td></tr><tr><td><code>files.metadata.read</code></td><td>Evet</td><td>Yol kontrolleri için dosya ve klasör metadatasını okur</td></tr><tr><td><code>files.metadata.write</code></td><td>Evet</td><td>Klasör oluşturur ve metadata yazar</td></tr><tr><td><code>files.content.write</code></td><td>Evet</td><td>Dosya yükler. Bu scope eksikse <code>required scope &#39;files.content.write&#39;</code> hatası alınır.</td></tr><tr><td><code>files.content.read</code></td><td>Önerilir</td><td>İndirme, önizleme ve geçici dosya bağlantılarına izin verir</td></tr></tbody></table><p>Scopes seçildikten sonra sayfanın altındaki <code>Submit</code> düğmesine tıklayın.</p><p><img src="'+r+'" alt="İzinleri ekleme" loading="lazy"></p><p>Önemli:</p><table tabindex="0"><thead><tr><th>Durum</th><th>Ne yapılmalı</th></tr></thead><tbody><tr><td>Scopes değiştirdiniz</td><td>Token yetkilendirme akışını yeniden çalıştırın ve yeni <code>Refresh Token</code> alın.</td></tr><tr><td>Yeniden yetkilendirme yapmadınız</td><td>Eski token yeni permissions değerlerini kazanmaz, bu yüzden yüklemeler hâlâ başarısız olabilir.</td></tr></tbody></table><h3 id="_4-app-credentials-degerlerini-kopyalayın" tabindex="-1">4. App Credentials Değerlerini Kopyalayın <a class="header-anchor" href="#_4-app-credentials-degerlerini-kopyalayın" aria-label="Permalink to &quot;4. App Credentials Değerlerini Kopyalayın&quot;">​</a></h3><p>Dropbox app sayfasından şu iki değeri kaydedin:</p><table tabindex="0"><thead><tr><th>Dropbox Alanı</th><th>ImgBed Alanı</th></tr></thead><tbody><tr><td><code>App key</code></td><td><code>App Key</code></td></tr><tr><td><code>App secret</code></td><td><code>App Secret</code></td></tr></tbody></table><h3 id="_5-dropbox-kanalını-doldurun" tabindex="-1">5. Dropbox Kanalını Doldurun <a class="header-anchor" href="#_5-dropbox-kanalını-doldurun" aria-label="Permalink to &quot;5. Dropbox Kanalını Doldurun&quot;">​</a></h3><p>Yükleme Ayarları&#39;nda <code>Dropbox</code> seçin ve şunları doldurun:</p><table tabindex="0"><thead><tr><th>ImgBed Alanı</th><th>Ne girilir</th></tr></thead><tbody><tr><td>Channel name</td><td>Tanınabilir bir ad, örneğin <code>Main Dropbox</code></td></tr><tr><td>App Key</td><td>Dropbox <code>App key</code></td></tr><tr><td>App Secret</td><td>Dropbox <code>App secret</code></td></tr><tr><td>Refresh Token</td><td>Şimdilik boş bırakın</td></tr><tr><td>Root directory</td><td>İsteğe bağlı. Varsayılan <code>imgbed</code>.</td></tr><tr><td>Note</td><td>İsteğe bağlı</td></tr></tbody></table><p><img src="'+d+'" alt="Token alma" loading="lazy"></p><h3 id="_6-refresh-token-alın" tabindex="-1">6. Refresh Token Alın <a class="header-anchor" href="#_6-refresh-token-alın" aria-label="Permalink to &quot;6. Refresh Token Alın&quot;">​</a></h3><ol><li>ImgBed&#39;de <code>Get Token</code> düğmesine tıklayın.</li><li>Bağlamak istediğiniz Dropbox hesabıyla giriş yapın.</li><li>Yetkilendirme istemini onaylayın.</li><li>Callback sayfası bir <code>Refresh Token</code> gösterir.</li><li>Bunu kopyalayın.</li><li>ImgBed&#39;e dönüp <code>Refresh Token</code> alanına yapıştırın.</li></ol><p><img src="'+n+'" alt="Token kopyalama" loading="lazy"></p><h2 id="nasıl-kontrol-edilir" tabindex="-1">Nasıl Kontrol Edilir? <a class="header-anchor" href="#nasıl-kontrol-edilir" aria-label="Permalink to &quot;Nasıl Kontrol Edilir?&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Kontrol</th><th>Beklenen sonuç</th></tr></thead><tbody><tr><td>Kanal kartı</td><td>Kaydettikten sonra Dropbox kanalı görünür.</td></tr><tr><td>Kanal anahtarı</td><td>Kanal etkinleştirilebilir.</td></tr><tr><td>Token kaydedildi</td><td>Ayrıntı sayfasında <code>Refresh Token</code> değerinin kaydedildiği görünür.</td></tr><tr><td>Test yüklemesi</td><td>Test görseli Dropbox app folder içinde görünür.</td></tr></tbody></table><p>Quota limits etkinse kota sorgusuna tıklayın. Başarılı sorgudan sonra kanal kartı kullanılan alanı, toplam alanı ve son güncelleme zamanını gösterir.</p><p><img src="'+o+`" alt="Kota sorgusu başarılı" loading="lazy"></p><h2 id="sorun-giderme" tabindex="-1">Sorun Giderme <a class="header-anchor" href="#sorun-giderme" aria-label="Permalink to &quot;Sorun Giderme&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Sorun</th><th>Çözüm</th></tr></thead><tbody><tr><td>ImgBed yapılandırmanın eksik olduğunu söylüyor</td><td><code>App Key</code>, <code>App Secret</code> ve <code>Refresh Token</code> alanlarının dolu olduğunu kontrol edin.</td></tr><tr><td>Yetkilendirme başarılı ama <code>Refresh Token</code> görünmüyor</td><td><code>Get Token</code> düğmesine tekrar tıklayın ve offline authorization flow kullanıldığından emin olun.</td></tr><tr><td>Yükleme <code>required scope &#39;files.content.write&#39;</code> hatasıyla başarısız oluyor</td><td><code>files.content.write</code> etkinleştirin, <code>Submit</code> tıklayın ve yeni <code>Refresh Token</code> alın.</td></tr><tr><td>Callback başarısız oluyor</td><td>Redirect URI değerinin <code>https://your-domain.com/api/oauth/dropbox/callback</code> olduğunu doğrulayın.</td></tr><tr><td>Dosyalar bulunamıyor</td><td>Dropbox app&#39;in <code>App folder</code> modunda oluşturulduğunu doğrulayın.</td></tr></tbody></table><h2 id="kısa-akıs" tabindex="-1">Kısa Akış <a class="header-anchor" href="#kısa-akıs" aria-label="Permalink to &quot;Kısa Akış&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Dropbox App Console&#39;u aç</span></span>
<span class="line"><span>-&gt; App oluştur</span></span>
<span class="line"><span>-&gt; App folder access seç</span></span>
<span class="line"><span>-&gt; https://your-domain.com/api/oauth/dropbox/callback ekle</span></span>
<span class="line"><span>-&gt; account_info.read / files.metadata.read / files.metadata.write / files.content.write etkinleştir</span></span>
<span class="line"><span>-&gt; İsteğe bağlı olarak files.content.read etkinleştir</span></span>
<span class="line"><span>-&gt; Submit tıkla</span></span>
<span class="line"><span>-&gt; App Key ve App Secret kopyala</span></span>
<span class="line"><span>-&gt; ImgBed&#39;e gir</span></span>
<span class="line"><span>-&gt; Get Token tıkla</span></span>
<span class="line"><span>-&gt; Callback sayfasından Refresh Token kopyala</span></span>
<span class="line"><span>-&gt; ImgBed&#39;e yapıştır ve kaydet</span></span></code></pre></div><h2 id="kaynaklar" tabindex="-1">Kaynaklar <a class="header-anchor" href="#kaynaklar" aria-label="Permalink to &quot;Kaynaklar&quot;">​</a></h2><ol><li>Dropbox App Console: <a href="https://www.dropbox.com/developers/apps" target="_blank" rel="noreferrer">https://www.dropbox.com/developers/apps</a></li><li>Dropbox OAuth Guide: <a href="https://developers.dropbox.com/oauth-guide" target="_blank" rel="noreferrer">https://developers.dropbox.com/oauth-guide</a></li><li>Dropbox Developer Guide: <a href="https://www.dropbox.com/developers/reference/developer-guide" target="_blank" rel="noreferrer">https://www.dropbox.com/developers/reference/developer-guide</a></li></ol>`,45)])])}const v=l(c,[["render",u]]);export{f as __pageData,v as default};
